const defaults = {
  topic: 'AI workflow automation',
  subject: 'solo creator at desk',
  goal: 'make a short-form explainer clip',
  emotion: 'curiosity and confidence',
  platform: 'youtube_shorts',
  theme: 'explainer',
  duration_sec: 20,
  style: 'cinematic',
  output_format: 'generic',
  language: 'en',
  budget_tier: 'low',
  quality_tier: 'balanced',
  preferred_engine: 'local',
  trend_aware: false,
};

const allowedPlatforms = new Set(['youtube_shorts', 'tiktok', 'instagram_reels']);
const allowedOutputs = new Set(['kling', 'runway', 'veo', 'pika', 'capcut', 'generic', 'human']);
const stylePresets = {
  cinematic: {
    hook_type: 'curiosity',
    pacing_profile: 'fast_cut',
    caption_style: 'tiktok_viral',
    camera_language: 'simple_push_in',
  },
  documentary: {
    hook_type: 'problem_first',
    pacing_profile: 'measured_ramp',
    caption_style: 'clean_editorial',
    camera_language: 'observational_handheld',
  },
  viral: {
    hook_type: 'pattern_break',
    pacing_profile: 'hyper_punchy',
    caption_style: 'tiktok_viral',
    camera_language: 'whip_pan',
  },
  editorial: {
    hook_type: 'authority_claim',
    pacing_profile: 'confident_climb',
    caption_style: 'clean_editorial',
    camera_language: 'locked_frame',
  },
  cozy: {
    hook_type: 'soft_surprise',
    pacing_profile: 'gentle_build',
    caption_style: 'subtle_minimal',
    camera_language: 'slow_dolly',
  },
};

const normalizePlatform = (value) => {
  const platform = String(value ?? defaults.platform).trim().toLowerCase();
  if (platform === 'youtube') return 'youtube_shorts';
  if (platform === 'reels' || platform === 'instagram') return 'instagram_reels';
  return allowedPlatforms.has(platform) ? platform : defaults.platform;
};

const normalizeStyle = (value) => {
  const key = String(value ?? defaults.style).trim().toLowerCase();
  return stylePresets[key] ? key : defaults.style;
};

const normalizeOutput = (value) => {
  const output = String(value ?? defaults.output_format).trim().toLowerCase();
  return allowedOutputs.has(output) ? output : defaults.output_format;
};

const buildEngineCommand = ({ projectPath, requestB64, outputFormat, comfyuiUrl, telegramChatId, trendAware }) => {
  const script = [
    "const fs=require('fs');",
    "const path=require('path');",
    "const cp=require('child_process');",
    "const projectPath=process.argv[1];",
    "const requestB64=process.argv[2];",
    "const outputFormat=process.argv[3];",
    "const comfyuiUrl=process.argv[4];",
    "const telegramChatId=process.argv[5];",
    "const trendAware=process.argv[6]==='true';",
    "if(!projectPath){",
    "  process.stdout.write(JSON.stringify({ fatal_error:'SHORTS_ENGINE_PATH is not configured', hint:'Set SHORTS_ENGINE_PATH in n8n or pass project_path in the trigger payload.', output_format:outputFormat, comfyui_url:comfyuiUrl, telegram_chat_id:telegramChatId }));",
    "  process.exit(0);",
    "}",
    "const requestJson=Buffer.from(requestB64,'base64').toString('utf8');",
    "const requestFile=path.join(projectPath,'n8n','request.runtime.json');",
    "fs.mkdirSync(path.dirname(requestFile),{recursive:true});",
    "fs.writeFileSync(requestFile,requestJson);",
    "const args=['--prefix',projectPath,'run','engine','--','format',requestFile,'--output',outputFormat,'--json'];",
    "if(trendAware) args.push('--trend-aware');",
    "const result=cp.spawnSync('npm',args,{encoding:'utf8',cwd:projectPath,shell:true});",
    "const stdout=String(result.stdout||'').trim();",
    "const stderr=String(result.stderr||'').trim();",
    "let cliResult=null;",
    "try { cliResult = stdout ? JSON.parse(stdout) : null; } catch (error) { cliResult = { fatal_error:'CLI returned non-JSON output', raw_stdout:stdout }; }",
    "const envelope={ project_path:projectPath, request_file:requestFile, output_format:outputFormat, comfyui_url:comfyuiUrl, telegram_chat_id:telegramChatId, cli_result:cliResult, engine_exit_code: result.status ?? 0, engine_stdout:stdout, engine_stderr:stderr };",
    "process.stdout.write(JSON.stringify(envelope));",
  ].join('');

  return `node -e \"${script}\" \"${projectPath}\" \"${requestB64}\" \"${outputFormat}\" \"${comfyuiUrl}\" \"${telegramChatId}\" \"${String(trendAware)}\"`;
};

return $input.all().map((item, index) => {
  const payload = item.json.body ?? item.json ?? {};
  const projectPath = String(payload.project_path ?? $env.SHORTS_ENGINE_PATH ?? '').trim().replace(/\\/g, '/').replace(/\/$/, '');
  const styleKey = normalizeStyle(payload.style);
  const outputFormat = normalizeOutput(payload.output_format);
  const request = {
    version: '0.1',
    intent: {
      topic: String(payload.topic ?? defaults.topic),
      subject: String(payload.subject ?? defaults.subject),
      goal: String(payload.goal ?? defaults.goal),
      emotion: String(payload.emotion ?? defaults.emotion),
      platform: normalizePlatform(payload.platform),
      theme: String(payload.theme ?? defaults.theme),
      duration_sec: Number(payload.duration_sec ?? defaults.duration_sec),
    },
    constraints: {
      language: String(payload.language ?? defaults.language),
      budget_tier: String(payload.budget_tier ?? defaults.budget_tier),
      quality_tier: String(payload.quality_tier ?? defaults.quality_tier),
      visual_consistency_required: payload.visual_consistency_required ?? true,
      content_policy_safe: payload.content_policy_safe ?? true,
    },
    style: stylePresets[styleKey],
    backend: {
      preferred_engine: String(payload.preferred_engine ?? defaults.preferred_engine),
      allow_fallback: payload.allow_fallback ?? true,
    },
    output: {
      type: 'video_prompt',
    },
  };

  const requestB64 = Buffer.from(JSON.stringify(request, null, 2), 'utf8').toString('base64');
  const comfyuiUrl = String(payload.comfyui_url ?? $env.COMFYUI_URL ?? '').trim();
  const telegramChatId = String(payload.telegram_chat_id ?? $env.TELEGRAM_CHAT_ID ?? '').trim();
  const trendAware = Boolean(payload.trend_aware ?? defaults.trend_aware);

  return {
    json: {
      index,
      source: item.json.body ? 'webhook' : 'manual',
      input: payload,
      request,
      project_path: projectPath,
      output_format: outputFormat,
      comfyui_url: comfyuiUrl,
      telegram_chat_id: telegramChatId,
      trend_aware: trendAware,
      engine_command: buildEngineCommand({
        projectPath,
        requestB64,
        outputFormat,
        comfyuiUrl,
        telegramChatId,
        trendAware,
      }),
    },
  };
});

return $input.all().map((item) => {
  const raw = String(item.json.stdout ?? '').trim();
  let parsed;

  try {
    parsed = raw ? JSON.parse(raw) : { fatal_error: 'Execute Command returned no stdout' };
  } catch (error) {
    parsed = {
      fatal_error: 'Execute Command returned invalid JSON',
      raw_stdout: raw,
      raw_stderr: String(item.json.stderr ?? ''),
    };
  }

  return {
    json: {
      ...parsed,
      kling_prompt: parsed?.output_format === 'kling' ? parsed?.cli_result?.content ?? '' : '',
      has_error: Boolean(parsed?.cli_result?.fatal_error || parsed?.fatal_error || parsed?.engine_exit_code),
    },
  };
});
